VALUES
  ('medical-tech-moex-09698', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '65歲的老王出車禍造成其左側肋骨斷裂 12天後老王的身體左側劇痛，並在該處出現泡狀皮疹（vesicular rash），症狀持續 數週。泡狀皮疹最有可能是由以下何病因引起？', '["EB病毒（Epstein-Barr virus）復發（reactivation）", "B型肝炎病毒（hepatitis B virus） 初次感染（primary infection）", "水痘病毒（varicella-zoster virus）復發", "人類疱疹病毒第二型（herpes simplex virus type 2）初次感染"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 73, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-09699', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有關腺病毒（adenovirus）的敘述，下列何者錯誤？', '["腺病毒可出現於感染者的呼吸道分泌物及糞便中", "常見的感染症狀包括呼吸道感染、結膜角膜炎及腸胃道感染", "腺病毒主要感染呼吸道、腸胃道及結膜角膜的黏膜上皮細胞", "目前尚無疫苗可以用來預防感染"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 74, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-09700', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有關狂犬病毒（rabies virus）的敘述，下列何者錯誤？', '["狂犬病毒會存在於感染動物之唾液，可藉由咬傷傳播病毒", "狂犬病毒入侵人體後，首先感染周邊神經細胞或肌細胞，然後沿神經細胞入侵中樞神經系統", "哺乳類動物、鳥類及蝙蝠等都容易被狂犬病毒感染且會發病", "狂犬病毒感染後若無適當治療則容易引發腦炎及自主神經系統壞死"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 75, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-09701', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '有關登革病毒感染的敘述，何者錯誤？', '["屬於節肢動物攜帶病毒之感染疾病", "目前快篩試劑主要檢測NS5抗原", "典型臨床症狀為發燒、頭痛、肌肉與骨骼關節酸痛", "secondary infection 常會造成出血性登革熱（dengue hemorrhagic fever）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 76, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-09702', 'medical-tech', 'medical-tech-moex-105-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '關於登革熱（dengue fever）與黃熱病（yellow fever）的敘述，下列何者錯誤？', '["均藉由埃及斑蚊叮咬傳播", "血清學檢驗上兩者無交叉免疫反應（cross-immune reaction）", "兩者在受感染之患者身上產生症狀相似，例如：冷顫、發燒、頭痛、背痛、全身肌肉痛等", "目前黃熱病有疫苗可以接種預防"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:38+00:00", "source_pdf_sha1": "b6f41ee075ab", "answer_pdf_sha1": "29c004a78149", "source_family": "moex-gov-tw", "moex": {"exam_code": "105100", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "105", "exam_name": "105年第二次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 77, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
